"""RBAC Models for Grantwise.

Defines roles, permissions, and the role registry.
"""
from enum import Enum
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Set


class PermissionEffect(Enum):
    """Whether a permission entry allows or denies access."""
    ALLOW = "allow"
    DENY = "deny"


@dataclass
class PermissionEntry:
    """A single permission entry in a role."""
    resource: str       # Resource pattern, e.g., 'grant:*', 'grant:123', 'budget:*'
    action: str         # Action, e.g., 'read', 'write', 'delete', 'admin'
    effect: PermissionEffect  # ALLOW or DENY


@dataclass
class Role:
    """A role definition with permissions and optional parent roles."""
    name: str
    description: str = ""
    permissions: List[PermissionEntry] = field(default_factory=list)
    parent_roles: List[str] = field(default_factory=list)  # Names of parent roles

    def add_permission(self, resource: str, action: str, effect: PermissionEffect):
        """Add a permission entry to this role."""
        self.permissions.append(PermissionEntry(resource=resource, action=action, effect=effect))


class RoleRegistry:
    """Registry that stores all role definitions and supports lookup."""

    def __init__(self):
        self._roles: Dict[str, Role] = {}

    def register_role(self, role: Role):
        """Register a role definition."""
        self._roles[role.name] = role

    def get_role(self, name: str) -> Optional[Role]:
        """Get a role by name, returns None if not found."""
        return self._roles.get(name)

    def get_all_roles(self) -> List[Role]:
        """Get all registered roles."""
        return list(self._roles.values())

    def get_parent_roles(self, role_name: str) -> List[Role]:
        """Get the parent roles of a given role."""
        role = self._roles.get(role_name)
        if not role:
            return []
        return [self._roles[p] for p in role.parent_roles if p in self._roles]


@dataclass
class User:
    """A user with assigned roles."""
    user_id: str
    email: str
    roles: List[str] = field(default_factory=list)  # Role names assigned to user
    resource_acls: Dict[str, List[PermissionEntry]] = field(default_factory=dict)  # Resource-specific overrides


def matches_resource(pattern: str, resource: str) -> bool:
    """Check if a resource pattern matches a specific resource.

    Supports wildcard matching:
    - 'grant:*' matches 'grant:123', 'grant:456', etc.
    - 'grant:123' matches only 'grant:123'
    - '*' matches everything
    """
    if pattern == '*':
        return True
    if '*' in pattern:
        prefix = pattern.split('*')[0]
        return resource.startswith(prefix)
    return pattern == resource

