      "permissions": [
        {"resource": "budget:*", "action": "write", "effect": "allow"},
        {"resource": "budget:*", "action": "approve", "effect": "allow"}
      ],
      "parent_roles": ["researcher"]
    },
    {
      "name": "dept_admin",
      "description": "Department administrator with broad access",
      "permissions": [
        {"resource": "grant:*", "action": "delete", "effect": "allow"},
        {"resource": "user:*", "action": "read", "effect": "allow"},
        {"resource": "user:*", "action": "write", "effect": "allow"}
      ],
      "parent_roles": ["pi"]
    },
    {
      "name": "auditor",
      "description": "Read-only auditor with explicit deny on writes",
      "permissions": [
        {"resource": "grant:*", "action": "read", "effect": "allow"},
        {"resource": "budget:*", "action": "read", "effect": "allow"},
        {"resource": "grant:*", "action": "write", "effect": "deny"},
        {"resource": "budget:*", "action": "write", "effect": "deny"}
      ],
      "parent_roles": []
    },
    {
      "name": "restricted_pi",
      "description": "PI with restricted budget approval inherited from auditor deny",
      "permissions": [
        {"resource": "budget:*", "action": "approve", "effect": "allow"}
      ],
      "parent_roles": ["auditor"]
    },
    {
      "name": "institution_admin",
      "description": "Top-level admin for the institution",
      "permissions": [
        {"resource": "*", "action": "admin", "effect": "allow"}
      ],
      "parent_roles": ["dept_admin"]
    }
  ]
}
